import React from "react";
import {reduxForm} from "redux-form";
import {Area, createField} from "../../Common/FormsControls/FormsControls";
import styles from "../../Common/FormsControls/FormsControls.module.css";
const Input = Area('input')
const Textarea = Area('textarea')

const ProfileDataForm = ({handleSubmit, profile, error}) => {
       return <form onSubmit={handleSubmit}>
        <div>
            <button>Save</button>
        </div>
        {error && <div className={styles.formSummeryError}>
            {error}
        </div>}
        {/*<ul className={classes.profiletext}>*/}
            <div><b>Полное имя:</b> {createField(Input, 'Full Name', 'fullName', 'text', [])} </div>
            {/*<div><b>Полное имя:</b> {createFieldProfile('Full Name', 'fullName', [], Input, [])} </div>*/}
        <div><b>О себе:</b>
            {createField(Textarea, 'About My', 'aboutMe', 'text', [])}
            </div>
                   <li><b>Мои контакты:</b></li>
            <div>
                <b>Contacts</b>: {Object.keys(profile.contacts).map(key => {
                return <div key={key}>
                    <b>{key}: {createField(Input, key, 'contacts.' + key, 'text', [])}</b>
                </div>
            })}
            </div>
            <div><b>В поиске работы?</b>
                {createField('Input', '', 'lookingForAJob', 'checkbox', [])}
                {/*{createField('Input', '', 'lookingForAJob', 'radio', [])}*/}
                {/*{createField('Input', '', 'lookingForAJob', 'radio', [])}*/}
            </div>
        {/*        <img src={profile.lookingForAJob ? yesLogo : noLogo}*/}
        {/*             alt={'AnswerLogo'}/></li>*/}
        <div><b> Професииональный опыт (описание поиска работы):</b>
        {createField(Textarea, 'My professional skills', 'lookingForAJobDescription', 'text', [])}
        </div>
    </form>
}

const ProfileDataFormReduxForm = reduxForm({
    form: 'edit-profile'
}) (ProfileDataForm)

export default ProfileDataFormReduxForm;

